import 'package:flutter/material.dart';
import 'package:flutter/scheduler.dart';

void main() => runApp(const MaterialApp(home: FrameDemo()));

class FrameDemo extends StatefulWidget {
  const FrameDemo({super.key});
  @override State<FrameDemo> createState() => _FrameDemoState();
}

class _FrameDemoState extends State<FrameDemo> {
  int _tick = 0;

  @override
  void initState() {
    super.initState();
    // Log every frame the pipeline runs — you'll see it ~60 times per second.
    SchedulerBinding.instance.addPostFrameCallback(_onFrame);
  }

  void _onFrame(Duration t) {
    debugPrint('[frame] t=${t.inMilliseconds}ms tick=$_tick');
    // Ask for the next frame — sustains the loop.
    SchedulerBinding.instance.addPostFrameCallback(_onFrame);
  }

  @override
  Widget build(BuildContext context) {
    debugPrint('[build] tick=$_tick');
    return Scaffold(
      appBar: AppBar(title: const Text('Pipeline demo')),
      body: Center(
        // A RepaintBoundary around the changing part — its neighbors are STATIC.
        // Enable DevTools' 'Highlight Repaints' to see only this box flash.
        child: RepaintBoundary(
          child: Container(
            width: 100 + (_tick % 100).toDouble(),
            height: 100 + (_tick % 100).toDouble(),
            color: Colors.deepPurple.withOpacity(0.6),
            child: Center(child: Text('$_tick')),
          ),
        ),
      ),
      floatingActionButton: FloatingActionButton(
        onPressed: () => setState(() => _tick++),
        child: const Icon(Icons.play_arrow),
      ),
    );
  }
}

// What to observe:
//  * [build] fires once per setState. If you also add a PerformanceOverlay,
//    you'll see the UI bar (top) tick a tiny amount, and the Raster bar
//    (bottom) tick separately.
//  * With the RepaintBoundary, only the Container's layer re-records —
//    the AppBar and Scaffold don't. Toggle it off and watch neighboring
//    layers flash in Highlight Repaints.
